module RefModule (  
    input [15:0] data_in,  
    input RE,  
    input WE,  
    input CLK,  
    output reg [15:0] data_out  
);  
  wire [15:0] _tap_data_in = data_in & {16{1'b1}};

    reg [15:0] memory;  

    always @(posedge CLK) begin  
        if (WE)  
            memory <= data_in;  
        if (RE)  
            data_out <= memory;  
    end  
endmodule
